Formula.en-us:
v2((data, _) => {
  // Collapse on load if data is specified
  const missing = !!(data.DataContentType || data.DataQuery || false);
  return {
    value: missing,
    stop: true,
  };
});

v2((data, context) => {
  const qName = data.DataQuery;
  const suffix = qName ? ` (Query: ${qName})` : '';
  const missing = data.DataContentType || data.DataQuery || false;
  return `${data.default}: ${data.DataContentType || (missing ? '' : '⚠️')}${suffix}`;
});

v2((data, context) => {
  function emoji(on) { return on ? '✅' : '🚫'};

  return data.default
    .replace('[edit]', emoji(data.EnableEdit))
    .replace('[add]', emoji(data.EnableAdd))
    .replace('[delete]', emoji(data.EnableDelete));
});
